  ('dietitian-moex-01927', 'dietitian', 'dietitian-moex-107-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '「運動對健康很重要，您認為體育課重要嗎？」，此題目之設計，犯了下列何種編製問卷常見的錯誤？', '["題目含糊不清", "題目有暗示作用", "題目含有兩個主題", "題目超過受試者能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "0bfeb6891da2", "answer_pdf_sha1": "563ab781ede4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01928', 'dietitian', 'dietitian-moex-107-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '一份食物喜好度問卷問到「你喜歡吃橘子、香蕉、蘋果嗎？」，答案選項是「□非常喜歡□喜歡□普通 □不喜歡□非常不喜歡」，此題目設計有下列何種缺失？', '["採用引導性的問句", "發問不重要的問題", "題目探問敏感性個人隱私", "一個問題包含兩個以上概念"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "0bfeb6891da2", "answer_pdf_sha1": "563ab781ede4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01929', 'dietitian', 'dietitian-moex-107-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '學校輔導校園周遭商店販售高鈣食物，提升學生含鈣食物的可近性，此屬於社會生態模式（social ecological model）的那一種層次？', '["個人層面", "人際層面", "機構組織層面", "政策及系統層面"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "0bfeb6891da2", "answer_pdf_sha1": "563ab781ede4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01930', 'dietitian', 'dietitian-moex-107-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '營養師運用健康信念模式推行減鹽飲食計畫，為了貼切社區居民需求，因此在活動設計時，需要考慮「修 正因素」，以下何者不是修正因素？', '["參與活動者以老人占多數，菜色示範設計需要注意牙口問題", "社區活動多以廟埕和市場為主，在該處設大型活動看板宣導活動", "閩客混居地區，菜色示範設計需要注意口味和地方特產", "社區居民罹患糖尿病、高血壓、高脂血症、心臟病盛行率高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "0bfeb6891da2", "answer_pdf_sha1": "563ab781ede4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01931', 'dietitian', 'dietitian-moex-107-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '營養師教導婦女可以計算自己食物鐵攝取量，確定獲得充足的膳食鐵來源。根據PRECED-PROCEED模 式，請問以下說明何者正確？', '["某職場中婦女大學教育以上居多，多使用手機和網路，營養師擬運用網路輔助教學，此為行為與環境 （behavior and environment）的評價", "營養師運用公司體檢資料，邀請有缺鐵貧血風險的女性員工參加「鐵定女子好幸福」活動，此為教育 （education）方面診斷", "在課程前、後評估學員在膳食鐵方面的知識與態度，顯示知識與態度都有顯著改善，此為流行病學 （epidemiology）診斷", "學員使用手機拍照記錄個人3天飲食資料，計算個人膳食鐵攝取量，此為影響（impact）評價中的技能 的獲得"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "0bfeb6891da2", "answer_pdf_sha1": "563ab781ede4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01932', 'dietitian', 'dietitian-moex-107-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關討論教學法的敘述，下列何者錯誤？', '["可增加團體的向心力", "可節省教學時間", "可發展批判思考的能力", "適合爭議性的主題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "0bfeb6891da2", "answer_pdf_sha1": "563ab781ede4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
